import { type ReactNode } from 'react';

import {
  actionContainer,
  actionShortcut,
  actionText,
} from './ActionItem.sty.js';
import { SymbolAtom } from '../../../../tooltip-atoms/components/SymbolAtom.js';
import { TooltipItem } from '../../../section-components/TooltipItem/TooltipItem.js';
import type { TooltipItemProps } from '../../../types/tooltip.js';

/** @internal */
export interface ActionItemProps extends TooltipItemProps {
  text: ReactNode;
  icon: ReactNode;
  shortcut?: string;
  disabled?: boolean;
}

/**
 * @internal
 */
export const ActionItem = (props: ActionItemProps) => {
  const { text, icon, shortcut, disabled, ...tooltipItemProps } = props;

  return (
    <TooltipItem
      className={actionContainer({ disabled })}
      {...tooltipItemProps}
    >
      <SymbolAtom>{icon}</SymbolAtom>
      <div className={actionText}>{text}</div>
      <div className={actionShortcut}>{shortcut}</div>
    </TooltipItem>
  );
};
